args:
set -euo pipefail
scheme="$1"
case "$scheme" in
  a) frontend_port=5173 ;;
  b) frontend_port=5174 ;;
  c) frontend_port=5175 ;;
  *) echo "Unsupported UI scheme: $scheme" >&2; exit 1 ;;
esac
CHAIN_SUBCONVERTER_DEV_UP_FRONTEND_PORT="$frontend_port" "${workspaceFolder}/scripts/dev-up.sh" "$scheme"
